690:     private Fetch<K, V> pollForFetches(Timer timer) {
691:         long pollTimeout = coordinator == null ? timer.remainingMs() :
692:                 Math.min(coordinator.timeToNextPoll(timer.currentTimeMs()), timer.remainingMs());
693: 
694:         // if data is available already, return it immediately
695:         final Fetch<K, V> fetch = fetcher.collectFetch();
696:         if (!fetch.isEmpty()) {
697:             return fetch;
698:         }
699: 
700:         // send any new fetches (won't resend pending fetches)
701:         sendFetches();
702: 
703:         // We do not want to be stuck blocking in poll if we are missing some positions
704:         // since the offset lookup may be backing off after a failure
705: 
706:         // NOTE: the use of cachedSubscriptionHasAllFetchPositions means we MUST call
707:         // updateAssignmentMetadataIfNeeded before this method.
708:         if (!cachedSubscriptionHasAllFetchPositions && pollTimeout > retryBackoffMs) {
709:             pollTimeout = retryBackoffMs;
710:         }
711: 
712:         log.trace("Polling for fetches with timeout {}", pollTimeout);
713: 
714:         Timer pollTimer = time.timer(pollTimeout);
715:         client.poll(pollTimer, () -> {
716:             // since a fetch might be completed by the background thread, we need this poll condition
717:             // to ensure that we do not block unnecessarily in poll()
718:             return !fetcher.hasAvailableFetches();
719:         });
720:         timer.update(pollTimer.currentTimeMs());
721: 
722:         return fetcher.collectFetch();
