43: /**
44:  * {@code FetchCollector} operates at the {@link RecordBatch} level, as that is what is stored in the
45:  * {@link FetchBuffer}. Each {@link org.apache.kafka.common.record.Record} in the {@link RecordBatch} is converted
46:  * to a {@link ConsumerRecord} and added to the returned {@link Fetch}.
47:  *
48:  * @param <K> Record key type
49:  * @param <V> Record value type
50:  */
51: public class FetchCollector<K, V> {
52: 
53:     private final Logger log;
54:     private final ConsumerMetadata metadata;
55:     private final SubscriptionState subscriptions;
56:     private final FetchConfig fetchConfig;
57:     private final Deserializers<K, V> deserializers;
58:     private final FetchMetricsManager metricsManager;
59:     private final Time time;
60: 
61:     public FetchCollector(final LogContext logContext,
62:                           final ConsumerMetadata metadata,
63:                           final SubscriptionState subscriptions,
64:                           final FetchConfig fetchConfig,
65:                           final Deserializers<K, V> deserializers,
66:                           final FetchMetricsManager metricsManager,
67:                           final Time time) {
68:         this.log = logContext.logger(FetchCollector.class);
69:         this.metadata = metadata;
70:         this.subscriptions = subscriptions;
71:         this.fetchConfig = fetchConfig;
72:         this.deserializers = deserializers;
73:         this.metricsManager = metricsManager;
74:         this.time = time;
75:     }
