214:     /**
215:      * Initialize a CompletedFetch object.
216:      */
217:     protected CompletedFetch initialize(final CompletedFetch completedFetch) {
218:         final TopicPartition tp = completedFetch.partition;
219:         final Errors error = Errors.forCode(completedFetch.partitionData.errorCode());
220:         boolean recordMetrics = true;
221: 
222:         try {
223:             if (!subscriptions.hasValidPosition(tp)) {
224:                 // this can happen when a rebalance happened while fetch is still in-flight
225:                 log.debug("Ignoring fetched records for partition {} since it no longer has valid position", tp);
226:                 return null;
227:             } else if (error == Errors.NONE) {
228:                 final CompletedFetch ret = handleInitializeSuccess(completedFetch);
229:                 recordMetrics = ret == null;
230:                 return ret;
231:             } else {
232:                 handleInitializeErrors(completedFetch, error);
233:                 return null;
234:             }
235:         } finally {
236:             if (recordMetrics) {
237:                 completedFetch.recordAggregatedMetrics(0, 0);
238:             }
239: 
240:             if (error != Errors.NONE)
241:                 // we move the partition to the end if there was an error. This way, it's more likely that partitions for
242:                 // the same topic can remain together (allowing for more efficient serialization).
243:                 subscriptions.movePartitionToEnd(tp);
244:         }
245:     }
