247:     private CompletedFetch handleInitializeSuccess(final CompletedFetch completedFetch) {
248:         final TopicPartition tp = completedFetch.partition;
249:         final long fetchOffset = completedFetch.nextFetchOffset();
250: 
251:         // we are interested in this fetch only if the beginning offset matches the
252:         // current consumed position
253:         SubscriptionState.FetchPosition position = subscriptions.positionOrNull(tp);
254:         if (position == null || position.offset != fetchOffset) {
255:             log.debug("Discarding stale fetch response for partition {} since its offset {} does not match " +
256:                 "the expected offset {} or the partition has been unassigned", tp, fetchOffset, position);
257:             return null;
258:         }
259: 
260:         final FetchResponseData.PartitionData partition = completedFetch.partitionData;
261:         log.trace("Preparing to read {} bytes of data for partition {} with offset {}",
262:                 FetchResponse.recordsSize(partition), tp, position);
263:         Iterator<? extends RecordBatch> batches = FetchResponse.recordsOrFail(partition).batches().iterator();
264: 
265:         if (!batches.hasNext() && FetchResponse.recordsSize(partition) > 0) {
266:             // This should not happen with brokers that support FetchRequest/Response V4 or higher (i.e. KIP-74)
267:             throw new KafkaException("Failed to make progress reading messages at " + tp + "=" +
268:                     fetchOffset + ". Received a non-empty fetch response from the server, but no " +
269:                     "complete records were found.");
270:         }
271: 
272:         if (!updatePartitionState(partition, tp)) {
273:             return null;
274:         }
275: 
276:         completedFetch.setInitialized();
277:         return completedFetch;
278:     }
