252:     <K, V> List<ConsumerRecord<K, V>> fetchRecords(FetchConfig fetchConfig,
253:                                                    Deserializers<K, V> deserializers,
254:                                                    int maxRecords) {
255:         // Error when fetching the next record before deserialization.
256:         if (corruptLastRecord)
257:             throw new KafkaException("Received exception when fetching the next record from " + partition
258:                     + ". If needed, please seek past the record to "
259:                     + "continue consumption.", cachedRecordException);
260: 
261:         if (isConsumed)
262:             return Collections.emptyList();
263: 
264:         List<ConsumerRecord<K, V>> records = new ArrayList<>();
265: 
266:         try {
267:             for (int i = 0; i < maxRecords; i++) {
268:                 // Only move to next record if there was no exception in the last fetch. Otherwise, we should
269:                 // use the last record to do deserialization again.
270:                 if (cachedRecordException == null) {
271:                     corruptLastRecord = true;
272:                     lastRecord = nextFetchedRecord(fetchConfig);
273:                     corruptLastRecord = false;
274:                 }
275: 
276:                 if (lastRecord == null)
277:                     break;
278: 
279:                 Optional<Integer> leaderEpoch = maybeLeaderEpoch(currentBatch.partitionLeaderEpoch());
280:                 TimestampType timestampType = currentBatch.timestampType();
281:                 ConsumerRecord<K, V> record = parseRecord(deserializers, partition, leaderEpoch, timestampType, lastRecord);
282:                 records.add(record);
