578:     public void unsubscribe() {
579:         acquireAndEnsureOpen();
580:         try {
581:             fetcher.clearBufferedDataForUnassignedPartitions(Collections.emptySet());
582:             if (this.coordinator != null) {
583:                 this.coordinator.onLeavePrepare();
