593:     @Override
594:     public void assign(Collection<TopicPartition> partitions) {
595:         acquireAndEnsureOpen();
596:         try {
597:             if (partitions == null) {
598:                 throw new IllegalArgumentException("Topic partition collection to assign to cannot be null");
599:             } else if (partitions.isEmpty()) {
600:                 this.unsubscribe();
601:             } else {
602:                 for (TopicPartition tp : partitions) {
603:                     String topic = (tp != null) ? tp.topic() : null;
604:                     if (isBlank(topic))
605:                         throw new IllegalArgumentException("Topic partitions to assign to cannot have null or empty topic");
606:                 }
607:                 fetcher.clearBufferedDataForUnassignedPartitions(partitions);
608: 
609:                 // make sure the offsets of topic partitions the consumer is unsubscribing from
610:                 // are committed since there will be no following rebalance
611:                 if (coordinator != null)
612:                     this.coordinator.maybeAutoCommitOffsetsAsync(time.milliseconds());
613: 
614:                 log.info("Assigned to partition(s): {}", partitions.stream().map(TopicPartition::toString).collect(Collectors.joining(", ")));
615:                 if (this.subscriptions.assignFromUser(new HashSet<>(partitions)))
616:                     metadata.requestUpdateForNewTopics();
617:             }
618:         } finally {
619:             release();
620:         }
621:     }
